// ============================================================
// HydraNet - Users API Route
// Unified API for all user types: Admin, UtilityManager, DMAManager, Engineer
// Note: Engineers table is used for both 'engineer' and 'team_leader' roles
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'
import { hashPassword } from '@/lib/auth'
import type { EntityStatus } from '@prisma/client'

// User type definitions
type UserRole = 'admin' | 'utility_manager' | 'dma_manager' | 'engineer' | 'team_leader'

interface UserResponse {
  id: string
  email: string
  name: string
  role: UserRole
  phone: string | null
  status: EntityStatus
  utilityId: string | null
  utilityName: string | null
  dmaId: string | null
  dmaName: string | null
  branchId?: string | null
  branchName?: string | null
  teamId?: string | null
  teamName?: string | null
  createdAt: string
}

// GET /api/users - List all users
// Query params: role, utilityId, dmaId
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const role = searchParams.get('role') as UserRole | null
    const utilityId = searchParams.get('utilityId')
    const dmaId = searchParams.get('dmaId')

    const users: UserResponse[] = []

    // Fetch Admins
    if (!role || role === 'admin') {
      const admins = await prisma.admin.findMany({
        select: {
          id: true,
          email: true,
          name: true,
          phone: true,
          status: true,
          createdAt: true,
        },
        orderBy: { name: 'asc' },
      })
      users.push(
        ...admins.map((a) => ({
          id: a.id,
          email: a.email,
          name: a.name,
          role: 'admin' as UserRole,
          phone: a.phone,
          status: a.status,
          utilityId: null,
          utilityName: null,
          dmaId: null,
          dmaName: null,
          createdAt: a.createdAt.toISOString(),
        }))
      )
    }

    // Fetch Utility Managers
    if (!role || role === 'utility_manager') {
      const utilityManagers = await prisma.utilityManager.findMany({
        select: {
          id: true,
          email: true,
          name: true,
          phone: true,
          status: true,
          createdAt: true,
          utility: { select: { id: true, name: true } },
        },
        orderBy: { name: 'asc' },
      })
      users.push(
        ...utilityManagers.map((um) => ({
          id: um.id,
          email: um.email,
          name: um.name,
          role: 'utility_manager' as UserRole,
          phone: um.phone,
          status: um.status,
          utilityId: um.utility?.id || null,
          utilityName: um.utility?.name || null,
          dmaId: null,
          dmaName: null,
          createdAt: um.createdAt.toISOString(),
        }))
      )
    }

    // Fetch DMA Managers
    if (!role || role === 'dma_manager') {
      const dmaManagers = await prisma.dMAManager.findMany({
        where: {
          ...(utilityId ? { utilityId } : {}),
        },
        select: {
          id: true,
          email: true,
          name: true,
          phone: true,
          status: true,
          createdAt: true,
          utilityId: true,
          utility: { select: { id: true, name: true } },
          dma: { select: { id: true, name: true } },
        },
        orderBy: { name: 'asc' },
      })
      users.push(
        ...dmaManagers.map((dm) => ({
          id: dm.id,
          email: dm.email,
          name: dm.name,
          role: 'dma_manager' as UserRole,
          phone: dm.phone,
          status: dm.status,
          utilityId: dm.utilityId,
          utilityName: dm.utility?.name || null,
          dmaId: dm.dma?.id || null,
          dmaName: dm.dma?.name || null,
          createdAt: dm.createdAt.toISOString(),
        }))
      )
    }

    // Fetch Engineers (regular engineers)
    if (!role || role === 'engineer') {
      const engineers = await prisma.engineer.findMany({
        where: {
          role: 'engineer',
          ...(dmaId ? { dmaId } : {}),
        },
        select: {
          id: true,
          email: true,
          name: true,
          phone: true,
          status: true,
          createdAt: true,
          dma: { select: { id: true, name: true, utilityId: true, utility: { select: { name: true } } } },
          branch: { select: { id: true, name: true } },
          team: { select: { id: true, name: true } },
        },
        orderBy: { name: 'asc' },
      })
      users.push(
        ...engineers.map((e) => ({
          id: e.id,
          email: e.email,
          name: e.name,
          role: 'engineer' as UserRole,
          phone: e.phone,
          status: e.status,
          utilityId: e.dma?.utilityId || null,
          utilityName: e.dma?.utility?.name || null,
          dmaId: e.dma?.id || null,
          dmaName: e.dma?.name || null,
          branchId: e.branch?.id || null,
          branchName: e.branch?.name || null,
          teamId: e.team?.id || null,
          teamName: e.team?.name || null,
          createdAt: e.createdAt.toISOString(),
        }))
      )
    }

    // Fetch Team Leaders (from Engineer table with role='team_leader')
    if (!role || role === 'team_leader') {
      const teamLeaders = await prisma.engineer.findMany({
        where: {
          role: 'team_leader',
          ...(dmaId ? { dmaId } : {}),
        },
        select: {
          id: true,
          email: true,
          name: true,
          phone: true,
          status: true,
          createdAt: true,
          dma: { select: { id: true, name: true, utilityId: true, utility: { select: { name: true } } } },
          branch: { select: { id: true, name: true } },
          teamLeading: { select: { id: true, name: true } },
        },
        orderBy: { name: 'asc' },
      })
      users.push(
        ...teamLeaders.map((tl) => ({
          id: tl.id,
          email: tl.email,
          name: tl.name,
          role: 'team_leader' as UserRole,
          phone: tl.phone,
          status: tl.status,
          utilityId: tl.dma?.utilityId || null,
          utilityName: tl.dma?.utility?.name || null,
          dmaId: tl.dma?.id || null,
          dmaName: tl.dma?.name || null,
          branchId: tl.branch?.id || null,
          branchName: tl.branch?.name || null,
          teamId: tl.teamLeading?.id || null,
          teamName: tl.teamLeading?.name || null,
          createdAt: tl.createdAt.toISOString(),
        }))
      )
    }

    return NextResponse.json(users)
  } catch (error) {
    console.error('Error fetching users:', error)
    return NextResponse.json({ error: 'Failed to fetch users' }, { status: 500 })
  }
}

// POST /api/users - Create a new user
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // Validate required fields
    if (!data.name || !data.email || !data.role) {
      return NextResponse.json(
        { error: 'Name, email, and role are required' },
        { status: 400 }
      )
    }

    // Check for existing email across all user tables
    const existingAdmin = await prisma.admin.findUnique({ where: { email: data.email } })
    const existingUtilityManager = await prisma.utilityManager.findUnique({ where: { email: data.email } })
    const existingDmaManager = await prisma.dMAManager.findUnique({ where: { email: data.email } })
    const existingEngineer = await prisma.engineer.findUnique({ where: { email: data.email } })

    if (existingAdmin || existingUtilityManager || existingDmaManager || existingEngineer) {
      return NextResponse.json(
        { error: 'User with this email already exists' },
        { status: 400 }
      )
    }

    // Hash the password
    const hashedPassword = await hashPassword(data.password || 'password123')

    let user: UserResponse

    switch (data.role) {
      case 'admin': {
        const admin = await prisma.admin.create({
          data: {
            name: data.name,
            email: data.email,
            password: hashedPassword,
            phone: data.phone || null,
            status: (data.status as EntityStatus) || 'active',
          },
        })
        user = {
          id: admin.id,
          email: admin.email,
          name: admin.name,
          role: 'admin',
          phone: admin.phone,
          status: admin.status,
          utilityId: null,
          utilityName: null,
          dmaId: null,
          dmaName: null,
          createdAt: admin.createdAt.toISOString(),
        }
        break
      }

      case 'utility_manager': {
        const utilityManager = await prisma.utilityManager.create({
          data: {
            name: data.name,
            email: data.email,
            password: hashedPassword,
            phone: data.phone || null,
            status: (data.status as EntityStatus) || 'active',
            ...(data.utilityId && { utilityId: data.utilityId }),
          },
          include: { utility: { select: { id: true, name: true } } },
        })
        user = {
          id: utilityManager.id,
          email: utilityManager.email,
          name: utilityManager.name,
          role: 'utility_manager',
          phone: utilityManager.phone,
          status: utilityManager.status,
          utilityId: utilityManager.utility?.id || null,
          utilityName: utilityManager.utility?.name || null,
          dmaId: null,
          dmaName: null,
          createdAt: utilityManager.createdAt.toISOString(),
        }
        break
      }

      case 'dma_manager': {
        if (!data.utilityId) {
          return NextResponse.json(
            { error: 'utilityId is required for DMA managers' },
            { status: 400 }
          )
        }
        const dmaManager = await prisma.dMAManager.create({
          data: {
            name: data.name,
            email: data.email,
            password: hashedPassword,
            phone: data.phone || null,
            status: (data.status as EntityStatus) || 'active',
            utilityId: data.utilityId,
            ...(data.dmaId && { dmaId: data.dmaId }),
          },
          include: {
            utility: { select: { id: true, name: true } },
            dma: { select: { id: true, name: true } },
          },
        })
        user = {
          id: dmaManager.id,
          email: dmaManager.email,
          name: dmaManager.name,
          role: 'dma_manager',
          phone: dmaManager.phone,
          status: dmaManager.status,
          utilityId: dmaManager.utilityId,
          utilityName: dmaManager.utility?.name || null,
          dmaId: dmaManager.dma?.id || null,
          dmaName: dmaManager.dma?.name || null,
          createdAt: dmaManager.createdAt.toISOString(),
        }
        break
      }

      case 'engineer':
      case 'team_leader': {
        if (!data.dmaId || !data.branchId) {
          return NextResponse.json(
            { error: 'dmaId and branchId are required for engineers/team leaders' },
            { status: 400 }
          )
        }
        const engineer = await prisma.engineer.create({
          data: {
            name: data.name,
            email: data.email,
            password: hashedPassword,
            phone: data.phone || null,
            status: (data.status as EntityStatus) || 'active',
            role: data.role, // 'engineer' or 'team_leader'
            dmaId: data.dmaId,
            branchId: data.branchId,
            ...(data.teamId && { teamId: data.teamId }),
          },
          include: {
            dma: { select: { id: true, name: true, utilityId: true, utility: { select: { name: true } } } },
            branch: { select: { id: true, name: true } },
            team: { select: { id: true, name: true } },
          },
        })
        user = {
          id: engineer.id,
          email: engineer.email,
          name: engineer.name,
          role: data.role as UserRole,
          phone: engineer.phone,
          status: engineer.status,
          utilityId: engineer.dma?.utilityId || null,
          utilityName: engineer.dma?.utility?.name || null,
          dmaId: engineer.dma?.id || null,
          dmaName: engineer.dma?.name || null,
          branchId: engineer.branch?.id || null,
          branchName: engineer.branch?.name || null,
          teamId: engineer.team?.id || null,
          teamName: engineer.team?.name || null,
          createdAt: engineer.createdAt.toISOString(),
        }
        break
      }

      default:
        return NextResponse.json({ error: 'Invalid role' }, { status: 400 })
    }

    return NextResponse.json(user, { status: 201 })
  } catch (error) {
    console.error('Error creating user:', error)
    return NextResponse.json({ error: 'Failed to create user' }, { status: 500 })
  }
}

// PUT /api/users - Update a user
export async function PUT(request: NextRequest) {
  try {
    const data = await request.json()

    if (!data.id || !data.role) {
      return NextResponse.json({ error: 'User ID and role are required' }, { status: 400 })
    }

    const updateData: {
      name?: string
      email?: string
      phone?: string | null
      status?: EntityStatus
      password?: string
    } = {
      name: data.name,
      email: data.email,
      phone: data.phone || null,
      status: data.status as EntityStatus,
    }

    // Only update password if provided
    if (data.password) {
      updateData.password = await hashPassword(data.password)
    }

    let user: UserResponse

    switch (data.role) {
      case 'admin': {
        const admin = await prisma.admin.update({
          where: { id: data.id },
          data: updateData,
        })
        user = {
          id: admin.id,
          email: admin.email,
          name: admin.name,
          role: 'admin',
          phone: admin.phone,
          status: admin.status,
          utilityId: null,
          utilityName: null,
          dmaId: null,
          dmaName: null,
          createdAt: admin.createdAt.toISOString(),
        }
        break
      }

      case 'utility_manager': {
        // The utility relation is managed via utilityId on UtilityManager
        // No need to update Utility table - just update the utilityManager's utilityId

        const utilityManager = await prisma.utilityManager.update({
          where: { id: data.id },
          data: {
            ...updateData,
            ...(data.utilityId !== undefined && { utilityId: data.utilityId || null }),
          },
          include: { utility: { select: { id: true, name: true } } },
        })
        user = {
          id: utilityManager.id,
          email: utilityManager.email,
          name: utilityManager.name,
          role: 'utility_manager',
          phone: utilityManager.phone,
          status: utilityManager.status,
          utilityId: utilityManager.utility?.id || null,
          utilityName: utilityManager.utility?.name || null,
          dmaId: null,
          dmaName: null,
          createdAt: utilityManager.createdAt.toISOString(),
        }
        break
      }

      case 'dma_manager': {
        const dmaManager = await prisma.dMAManager.update({
          where: { id: data.id },
          data: {
            ...updateData,
            ...(data.dmaId !== undefined && { dmaId: data.dmaId || null }),
          },
          include: {
            utility: { select: { id: true, name: true } },
            dma: { select: { id: true, name: true } },
          },
        })
        user = {
          id: dmaManager.id,
          email: dmaManager.email,
          name: dmaManager.name,
          role: 'dma_manager',
          phone: dmaManager.phone,
          status: dmaManager.status,
          utilityId: dmaManager.utilityId,
          utilityName: dmaManager.utility?.name || null,
          dmaId: dmaManager.dma?.id || null,
          dmaName: dmaManager.dma?.name || null,
          createdAt: dmaManager.createdAt.toISOString(),
        }
        break
      }

      case 'engineer':
      case 'team_leader': {
        const engineer = await prisma.engineer.update({
          where: { id: data.id },
          data: {
            ...updateData,
            role: data.role,
            ...(data.teamId !== undefined && { teamId: data.teamId || null }),
          },
          include: {
            dma: { select: { id: true, name: true, utilityId: true, utility: { select: { name: true } } } },
            branch: { select: { id: true, name: true } },
            team: { select: { id: true, name: true } },
          },
        })
        user = {
          id: engineer.id,
          email: engineer.email,
          name: engineer.name,
          role: engineer.role as UserRole,
          phone: engineer.phone,
          status: engineer.status,
          utilityId: engineer.dma?.utilityId || null,
          utilityName: engineer.dma?.utility?.name || null,
          dmaId: engineer.dma?.id || null,
          dmaName: engineer.dma?.name || null,
          branchId: engineer.branch?.id || null,
          branchName: engineer.branch?.name || null,
          teamId: engineer.team?.id || null,
          teamName: engineer.team?.name || null,
          createdAt: engineer.createdAt.toISOString(),
        }
        break
      }

      default:
        return NextResponse.json({ error: 'Invalid role' }, { status: 400 })
    }

    return NextResponse.json(user)
  } catch (error) {
    console.error('Error updating user:', error)
    return NextResponse.json({ error: 'Failed to update user' }, { status: 500 })
  }
}

// DELETE /api/users - Delete a user
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')
    const role = searchParams.get('role') as UserRole | null

    if (!id || !role) {
      return NextResponse.json({ error: 'User ID and role are required' }, { status: 400 })
    }

    switch (role) {
      case 'admin':
        await prisma.admin.delete({ where: { id } })
        break
      case 'utility_manager':
        await prisma.utilityManager.delete({ where: { id } })
        break
      case 'dma_manager':
        await prisma.dMAManager.delete({ where: { id } })
        break
      case 'engineer':
      case 'team_leader':
        await prisma.engineer.delete({ where: { id } })
        break
      default:
        return NextResponse.json({ error: 'Invalid role' }, { status: 400 })
    }

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Error deleting user:', error)
    return NextResponse.json({ error: 'Failed to delete user' }, { status: 500 })
  }
}